function resolveModelConfig(modelStore, slot, fallback) {
	const state = modelStore.getState();
	if (typeof state.resolveModel === "function") {
		const resolved = state.resolveModel(slot) || fallback;
		const candidates = Array.isArray(resolved) ? resolved : [resolved];
		const primary = candidates[0] || fallback;
		return {
			provider: primary.provider,
			model: primary.model,
			temperature: primary.temperature,
			candidates
		};
	}
	const config = state.models?.[slot];
	if (Array.isArray(config)) {
		const primary = config[0] || fallback;
		return {
			provider: primary.provider,
			model: primary.model,
			temperature: primary.temperature,
			candidates: config
		};
	}
	return config ? {
		provider: config.provider,
		model: config.model,
		temperature: config.temperature,
		candidates: [config]
	} : {
		...fallback,
		candidates: [fallback]
	};
}
