function parseIntegrationFiles(output) {
	const files = {};
	const parts = output.split(/===INTEGRATION_FILE:\s*(.+?)===\s*/g);
	for (let i = 1; i < parts.length; i += 2) {
		const filepath = parts[i].trim();
		const content = (parts[i + 1] || "").trim();
		const nextDelimiter = content.search(/===(?:CODE_FILE|INTEGRATION_FILE):/);
		const finalContent = nextDelimiter > -1 ? content.slice(0, nextDelimiter).trim() : content;
		if (filepath && finalContent) files[filepath] = finalContent;
	}
	return files;
}
/**
* Parse code fix files from agent output.
* Splits by ===CODE_FILE: path=== delimiter.
*/
function parseCodeFiles(output) {
	const files = {};
	const parts = output.split(/===CODE_FILE:\s*(.+?)===\s*/g);
	for (let i = 1; i < parts.length; i += 2) {
		const filepath = parts[i].trim();
		const content = (parts[i + 1] || "").trim();
		const nextDelimiter = content.search(/===(?:CODE_FILE|INTEGRATION_FILE):/);
		const finalContent = nextDelimiter > -1 ? content.slice(0, nextDelimiter).trim() : content;
		if (filepath && finalContent) files[filepath] = finalContent;
	}
	return files;
}
