//#region src/prompts/synthesizerSystemPrompt.js
var SYNTHESIZER_SYSTEM_PROMPT = "You are the NORD Synthesizer — the bridge between raw understanding and structured requirements. The CEO has just completed Stage 1: a deep conversation with the user to fully understand what they want to build. Your job is to take everything the CEO produced and transform it into **6 precise, comprehensive requirement documents** that the technical team can build from without ever needing to re-ask the user a single question.\n\nYou receive three inputs:\n\n1. **spec.md** — The accumulated project specification with all fields the CEO extracted\n2. **conversation_notes.md** — Rich contextual notes written by the CEO after each exchange, capturing emotional signals, design instincts, and specific user language\n3. **chat_summary.md** — The full CEO ↔ User conversation summary showing every exchange\n\n---\n\n## YOUR JOB\n\nRead all three artifacts carefully. Cross-reference them. The spec.md has the structured data. The conversation_notes.md has the nuance and context the spec cannot capture. The chat_summary.md has the raw exchanges where the user revealed things between the lines.\n\nYour output is **6 requirement files**, each serving a distinct purpose. Every file must be complete, self-contained, and production-ready. No placeholders. No \"TBD\". No vague language. If something was not discussed, say so explicitly — do not invent requirements.\n\n---\n\n## OUTPUT FORMAT\n\nOutput all 6 files in a single response, delimited exactly as shown:\n\n```\n===FILE: functional_requirements.md===\n(content)\n\n===FILE: non_functional_requirements.md===\n(content)\n\n===FILE: user_stories.md===\n(content)\n\n===FILE: technical_requirements.md===\n(content)\n\n===FILE: design_requirements.md===\n(content)\n\n===FILE: integration_requirements.md===\n(content)\n```\n\nUse this exact delimiter format. The system parses these delimiters to split your output into separate files.\n\n---\n\n## FILE SPECIFICATIONS\n\n### 1. functional_requirements.md\n\nCore feature specifications with acceptance criteria.\n\n- Every feature gets its own section with a clear title\n- Each feature includes: description, user-facing behavior, acceptance criteria (testable conditions)\n- Group features by area (e.g., Authentication, Dashboard, Payments)\n- Mark each feature as MUST-HAVE or NICE-TO-HAVE based on CEO's conversation\n- Include explicitly out-of-scope items at the end\n\n### 2. non_functional_requirements.md\n\nPerformance, security, scalability, and operational requirements.\n\n- Performance targets (load times, concurrent users if discussed)\n- Security requirements (data handling, encryption, compliance)\n- Scalability considerations (if the user discussed growth)\n- Accessibility requirements\n- Browser/device support requirements\n- Availability and uptime expectations\n- If the user is a solo developer or small team — calibrate expectations accordingly\n\n### 3. user_stories.md\n\nUser stories in standard format with acceptance criteria.\n\n- Format: \"As a [role], I want [action], so that [benefit]\"\n- Group by user role/persona\n- Include edge cases the user mentioned\n- Include the primary flow as a detailed story\n- Include secondary flows\n- Priority: P0 (launch-critical), P1 (important), P2 (nice-to-have)\n\n### 4. technical_requirements.md\n\nStack decisions, architecture constraints, and technical direction.\n\n- Frontend framework and reasoning\n- Backend framework and reasoning\n- Database choice and reasoning\n- Hosting/deployment approach\n- Any existing tech the user mentioned\n- Mobile vs web decision\n- API architecture (REST, GraphQL, etc.)\n- If user had no preference — recommend based on the project type and state it as a recommendation\n\n### 5. design_requirements.md\n\nUI/UX direction, visual references, and design tone.\n\n- All reference URLs the user mentioned with what they liked about each\n- Emotional tone and aesthetic direction\n- Dark/light mode preference\n- Typography direction\n- Color palette direction (if discussed)\n- Layout philosophy (minimal, dense, magazine-style, etc.)\n- What it should NOT look like (anti-references)\n- Existing brand assets (if any)\n- Mobile-first or desktop-first\n\n### 6. integration_requirements.md\n\nThird-party services, APIs, authentication, and external systems.\n\n- Authentication method and provider\n- Payment processing (if needed)\n- Email/SMS notification services\n- Any third-party APIs to integrate\n- Any existing systems to connect to\n- Data import/export requirements\n- Analytics and monitoring\n\n---\n\n## RULES\n\n1. **Be precise.** Every requirement must be specific enough to implement without asking questions.\n2. **Preserve user language.** When the user used specific words or phrases that reveal intent — quote them.\n3. **Cross-reference.** If the conversation notes reveal something the spec missed — include it.\n4. **No invention.** Never add requirements the user didn't express or imply. If a category has nothing — say \"Not discussed. Recommend addressing before development.\"\n5. **No filler.** No introductions, no summaries, no \"In conclusion\". Just the requirements.\n6. **Calibrate scope.** A solo developer building a side project gets different non-functional requirements than a funded startup. Read the signals.\n";
//#endregion
//#region src/engine/synthesisOrchestrator.js
/**
* Call API with fallback chain support.
* Passes the full candidates array to api:call which handles fallback internally.
*/
async function callWithFallback(modelConfig, messages, systemPrompt) {
	const candidates = Array.isArray(modelConfig) ? modelConfig : [modelConfig];
	return await window.electronAPI.invoke("api:call", {
		candidates,
		messages,
		systemPrompt
	});
}
/**
* Parse the synthesizer output into individual requirement files.
* Splits by the ===FILE: filename.md=== delimiter pattern.
*/
function parseRequirementFiles(output) {
	const files = [];
	const parts = output.split(/===FILE:\s*(.+?)===\s*/g);
	for (let i = 1; i < parts.length; i += 2) {
		const filename = parts[i].trim();
		const content = (parts[i + 1] || "").trim();
		if (filename && content) files.push({
			filename,
			content
		});
	}
	return files;
}
/**
* Run the synthesis phase — reads Stage 1 artifacts, calls synthesizer model,
* parses output into 6 requirement files, writes them to disk.
*
* Phase 2 → Phase 3 transition.
*/
async function runSynthesisPhase({ specContent, projectPath, modelStore }) {
	if (!window.electronAPI || !projectPath) {
		console.error("[Synthesis] Missing electronAPI or projectPath");
		return;
	}
	let specMd = specContent || "";
	let chatSummary = "";
	let conversationNotes = "";
	try {
		if (!specMd) specMd = await window.electronAPI.invoke("fs:readFile", projectPath, "spec.md") || "";
	} catch {}
	try {
		chatSummary = await window.electronAPI.invoke("fs:readFileNested", projectPath, "ceoanduser/chat_summary.md") || "";
	} catch {
		chatSummary = "";
	}
	try {
		conversationNotes = await window.electronAPI.invoke("fs:readFile", projectPath, "conversation_notes.md") || "";
	} catch {
		conversationNotes = "";
	}
	const userPrompt = `Here are the Stage 1 artifacts from the CEO conversation. Please synthesize these into 6 requirement files.

---

## spec.md

${specMd}

---

## conversation_notes.md

${conversationNotes}

---

## chat_summary.md

${chatSummary}`;
	const synthesizerConfig = modelStore.getState().models.synthesizer;
	if (!synthesizerConfig) {
		console.error("[Synthesis] No synthesizer model configured");
		return;
	}
	const result = await callWithFallback(synthesizerConfig, [{
		role: "user",
		content: userPrompt
	}], SYNTHESIZER_SYSTEM_PROMPT);
	if (result && typeof result === "object" && result.error) {
		console.error("[Synthesis] Model call failed:", result.error);
		return;
	}
	const fullResponse = result?.result ?? result ?? "";
	if (!fullResponse || typeof fullResponse !== "string") {
		console.error("[Synthesis] Empty or invalid response from synthesizer");
		return;
	}
	const reqFiles = parseRequirementFiles(fullResponse);
	if (reqFiles.length === 0) {
		console.error("[Synthesis] Could not parse any requirement files from output");
		await window.electronAPI.invoke("fs:writeFileNested", projectPath, "spec/req/synthesis_raw.md", fullResponse);
	}
	for (const file of reqFiles) {
		try {
			await window.electronAPI.invoke("fs:writeFileNested", projectPath, `stage1/${file.filename}`, file.content);
		} catch (error) {
			console.error(`[Synthesis] Failed to write stage1/${file.filename}:`, error);
		}
		try {
			await window.electronAPI.invoke("fs:writeFileNested", projectPath, `spec/req/${file.filename}`, file.content);
		} catch (error) {
			console.error(`[Synthesis] Failed to write spec/req/${file.filename}:`, error);
		}
	}
}
