async function runResearchPhase({ specContent, projectId, projectPath, agentStore, projectStore, modelStore }) {
	const initializeAgent = (id, name, model, provider, temperature) => {
		if (agentStore.getState().agents[id]) agentStore.getState().updateAgent(id, {
			status: "idle",
			tokens: "",
			log: []
		});
		else agentStore.getState().setAgents({
			...agentStore.getState().agents,
			[id]: {
				id,
				name,
				model,
				provider,
				temperature,
				status: "idle",
				tokens: "",
				log: []
			}
		});
	};
	const resolveModel = (agentId) => {
		const stored = modelStore?.getState?.()?.models?.[agentId];
		const defaultAgent = RESEARCH_AGENTS.find((a) => a.id === agentId);
		if (stored) {
			const candidates = Array.isArray(stored) ? stored : [stored];
			const primary = candidates[0];
			return {
				provider: primary?.provider || defaultAgent?.provider || "groq",
				model: primary?.model || defaultAgent?.model || "",
				temperature: primary?.temperature ?? defaultAgent?.temperature ?? .2,
				candidates
			};
		}
		return defaultAgent ? {
			provider: defaultAgent.provider,
			model: defaultAgent.model,
			temperature: defaultAgent.temperature,
			candidates: [{
				provider: defaultAgent.provider,
				model: defaultAgent.model,
				temperature: defaultAgent.temperature
			}]
		} : {
			provider: "groq",
			model: "",
			temperature: .2,
			candidates: [{
				provider: "groq",
				model: "",
				temperature: .2
			}]
		};
	};
	RESEARCH_AGENTS.forEach((a) => {
		const resolved = resolveModel(a.id);
		initializeAgent(a.id, a.name, resolved.model, resolved.provider, resolved.temperature);
	});
	const scouts = RESEARCH_AGENTS.slice(0, 4);
	const userPrompts = scoutUserPrompts(specContent);
	const scoutResults = {
		scout_repo: "",
		scout_package: "",
		scout_api: "",
		scout_docs: ""
	};
	let updateListener = null;
	if (window.electronAPI) updateListener = window.electronAPI.on("agents:update", (payload) => {
		const { agentId, status, token } = payload;
		const agent = agentStore.getState().agents[agentId];
		if (agent) agentStore.getState().updateAgent(agentId, {
			status,
			tokens: (agent.tokens || "") + (token || ""),
			log: [...agent.log || [], token || ""]
		});
	});
	try {
		agentStore.getState().setAgents(Object.fromEntries(Object.entries(agentStore.getState().agents).map(([id, a]) => [id, {
			...a,
			status: "running"
		}])));
		(await Promise.allSettled(scouts.map((scout) => {
			const resolved = resolveModel(scout.id);
			return window.electronAPI ? window.electronAPI.invoke("agents:run", [{
				id: scout.id,
				name: scout.name,
				model: resolved.model,
				provider: resolved.provider,
				temperature: resolved.temperature,
				candidates: resolved.candidates,
				systemPrompt: scoutSystemPrompts[scout.id],
				userPrompt: userPrompts[scout.id]
			}]) : Promise.resolve("");
		}))).forEach((settled, idx) => {
			const scout = scouts[idx];
			let result = "";
			if (settled?.status === "fulfilled") {
				const inner = Array.isArray(settled.value) ? settled.value[0] : settled.value;
				result = normalizeResultContent(inner?.status === "fulfilled" ? inner.value : inner);
			}
			scoutResults[scout.id] = result;
			agentStore.getState().updateAgent(scout.id, {
				status: settled?.status === "fulfilled" ? "complete" : "failed",
				tokens: result
			});
		});
	} catch (error) {
		scouts.forEach((scout) => {
			agentStore.getState().updateAgent(scout.id, { status: "failed" });
		});
	} finally {
		if (updateListener) updateListener();
	}
	const consolidatorPrompt = `Here are the research findings from 4 scouts:

## Repo Scout
${scoutResults.scout_repo}

## Package Scout
${scoutResults.scout_package}

## API Scout
${scoutResults.scout_api}

## Docs Scout
${scoutResults.scout_docs}

Please consolidate these into a clean resource.md document.`;
	const consolidatorModel = resolveModel("consolidator");
	agentStore.getState().setAgents({
		...agentStore.getState().agents,
		consolidator: {
			id: "consolidator",
			name: "Consolidator",
			model: consolidatorModel.model,
			provider: consolidatorModel.provider,
			temperature: consolidatorModel.temperature,
			status: "running",
			tokens: "",
			log: []
		}
	});
	let consolidatedOutput = "";
	try {
		const candidates = consolidatorModel.candidates || [consolidatorModel];
		consolidatedOutput = normalizeResultContent(await window.electronAPI?.invoke("api:call", {
			candidates,
			messages: [{
				role: "user",
				content: consolidatorPrompt
			}],
			systemPrompt: CONSOLIDATOR_PROMPT
		}));
	} catch {
		consolidatedOutput = "";
	} finally {
		agentStore.getState().updateAgent("consolidator", {
			status: "complete",
			tokens: consolidatedOutput
		});
	}
	if (window.electronAPI && projectPath) await window.electronAPI.invoke("fs:writeFile", projectPath, "resource.md", consolidatedOutput);
	if (window.electronAPI && projectId) await window.electronAPI.invoke("db:updateProjectPhase", projectId, 5);
	projectStore.getState().setPhase(5);
	showToast("✓ Research complete", "success");
	window.dispatchEvent(new CustomEvent("nord:research-complete", { detail: {
		specContent,
		projectId,
		projectPath
	} }));
}
