function initPhaseTransitionListener() {
	window.addEventListener("nord:phase-transition", async (event) => {
		const { specContent, projectId, projectPath } = event.detail;
		await runSynthesisPhase({
			specContent,
			projectPath,
			modelStore: useModelStore
		});
		useProjectStore.getState().setPhase(3);
		showToast("✓ Spec locked — entering Design phase", "success");
		if (window.electronAPI && projectId) await window.electronAPI.invoke("db:updateProjectPhase", projectId, 3);
	});
	window.addEventListener("nord:design-complete", async (event) => {
		const { specContent, projectId, projectPath } = event.detail;
		useProjectStore.getState().setPhase(4);
		showToast("✓ Design complete — starting Research", "success");
		if (window.electronAPI && projectId) await window.electronAPI.invoke("db:updateProjectPhase", projectId, 4);
		await runResearchPhase({
			specContent,
			projectId,
			projectPath,
			agentStore: useAgentStore,
			projectStore: useProjectStore,
			modelStore: useModelStore
		});
	});
	window.addEventListener("nord:research-complete", (event) => {
		console.log("[Phase] Research complete — Stage 3 (Planning) is now active via phase-based prompt selection");
	});
	window.addEventListener("nord:plan-complete", async (event) => {
		const { projectId } = event.detail;
		useProjectStore.getState().setPhase(6);
		if (window.electronAPI && projectId) await window.electronAPI.invoke("db:updateProjectPhase", projectId, 6);
	});
	window.addEventListener("nord:build-complete", async (event) => {
		const { projectId } = event.detail;
		useProjectStore.getState().setPhase(7);
		if (window.electronAPI && projectId) await window.electronAPI.invoke("db:updateProjectPhase", projectId, 7);
	});
}
